const monthAgo = new Date(); monthAgo.setDate(1); monthAgo.setMonth(monthAgo.getMonth()-1);
const records = $input.all().map(i=>i.json).filter(r => r.date && new Date(r.date) >= monthAgo);
const total_mrr_lost = records.reduce((s,r)=>s+parseFloat(r.mrr_lost||0),0);
return [{ json: { records, count: records.length, total_mrr_lost: Math.round(total_mrr_lost), period: new Date().toISOString().slice(0,7) } }];

