const data = $('Filter This Month').first().json;
let analysis;
try { analysis = JSON.parse(($input.first().json.message?.content||'{}').replace(/```json|```/g,'').trim()); } catch { analysis = {}; }
return [{ json: { period: data.period, count: data.count, total_mrr_lost: data.total_mrr_lost, generated_at: new Date().toISOString(), ...analysis } }];

